import { notFound } from "next/navigation";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";
import { siteConfig } from "@/config/site-config";
import { getPayloadContent } from "@/lib/utils/get-payload-content";
import type { Faq } from "@/payload-types";

// Define types for static content structure
type StaticFaq = {
  id?: string;
  question: string;
  answer: string;
  category: string;
  order?: number;
};

const getAnswerText = (answer: unknown): string => {
  if (typeof answer === "string") return answer;
  if (typeof answer === "object" && answer && "root" in answer) {
    const richText = answer as { root: { children: { children?: { text: string }[] }[] } };
    return richText.root.children.map((child) => child.children?.[0]?.text || "").join("\n");
  }
  return "";
};

export default async function FaqPage() {
  let faqs: (Faq | StaticFaq)[] = [];

  try {
    faqs = await getPayloadContent<"faqs", StaticFaq[]>({
      collection: "faqs",
      options: { sort: "-order" },
      fallbackImport: async () => {
        const { content } = await import("@/content/faq/faq-content");
        // The content is already in the correct format for static FAQs
        return { content };
      },
    });
  } catch (error) {
    console.error("Error loading FAQs:", error);
    return null;
  }

  if (!faqs?.length) {
    return notFound();
  }

  return (
    <section className="container mx-auto mt-header space-y-section py-16">
      <div className="grid w-full grid-cols-1 md:grid-cols-5">
        <div className="z-10 col-span-2 bg-neutral-50 p-12 dark:bg-neutral-900">
          <h2 className="mb-4 text-3xl font-semibold tracking-tight text-neutral-900 dark:text-neutral-100">
            Frequently Asked Questions
          </h2>
          <p className="mb-8 text-neutral-600 dark:text-neutral-300">
            Here are some common questions about {siteConfig.title}. If you have any other
            questions, feel free to reach out to us.
          </p>
        </div>
        <div className="col-span-3 space-y-8 border-t border-neutral-400/15 bg-white px-20 py-12 dark:bg-neutral-950 md:border-l md:border-t-0">
          <Accordion type="single" collapsible className="w-full">
            {faqs.map((faq) => {
              const id = "id" in faq && faq.id ? faq.id.toString() : faq.question;
              const answerText = getAnswerText(faq.answer);

              return (
                <AccordionItem key={id} value={id}>
                  <AccordionTrigger className="text-xl font-medium tracking-tight text-neutral-800 dark:text-neutral-100">
                    {faq.question}
                  </AccordionTrigger>
                  <AccordionContent className="mt-2 leading-6 text-neutral-700 dark:text-neutral-400">
                    <p className="whitespace-pre-line">{answerText}</p>
                  </AccordionContent>
                </AccordionItem>
              );
            })}
          </Accordion>
        </div>
      </div>
    </section>
  );
}

import { SuspenseFallback } from "@/components/primitives/suspense-fallback";

export default function Loading() {
  return <SuspenseFallback />;
}

export const content = [
  {
    question: "What do I actually get?",
    answer:
      "A full Next.js 15 codebase. Auth (Auth.js v5), database (Postgres + Drizzle), payments (LemonSqueezy), CMS (Payload), email (Resend), 100+ UI components (shadcn/ui), AI integrations, and deployment configs. You clone the repo and own the code forever.",
    category: "general",
  },
  {
    question: "Is this a template or a framework?",
    answer:
      "Neither. It's a working app. Dashboard, landing pages, auth flows, admin panel. All built. Modify whatever you want, delete what you don't. There's no lock-in because it's just Next.js, TypeScript, and standard libraries.",
    category: "general",
  },
  {
    question:
      "I use Cursor, v0, or Windsurf. Does this work with AI coding tools?",
    answer:
      "Yes. Shipkit ships with Cursor rules, prompts, and project context files so AI tools understand the codebase from the start. Built for the AI-assisted workflow.",
    category: "technical",
  },
  {
    question: "Can non-developers use this?",
    answer:
      "There's a visual editor (Builder.io) and CMS (Payload) for managing content without code. For the rest, AI tools like Cursor can handle most setup and customization if you give them the right context. Shipkit includes that context.",
    category: "technical",
  },
  {
    question: "What if I don't need all the features?",
    answer:
      "Delete what you don't need. Don't want the CMS? Remove the Payload config. No AI? Drop those routes. It's your code.",
    category: "technical",
  },
  {
    question: "Is there a free version?",
    answer:
      "Shipkit Bones is free and open source. Core Next.js setup with auth and basic components. The paid version adds the database, payments, CMS, AI, and premium components.",
    category: "pricing",
  },
  {
    question: "Do I get updates?",
    answer: "Forever. You own the code, so you merge updates when you want.",
    category: "general",
  },
  {
    question: "Who built this?",
    answer:
      "One developer who's shipped 10+ production apps with this exact stack. Fly5, FPV Bible, Lacy Shell, Vibe Rehab, and this site all run on Shipkit. Not a company with investors and a marketing department. Just someone who uses this every day.",
    category: "general",
  },
];
